/// Looks up a tag descriptor by its canonical name.
///
/// # Arguments
/// * `name` - The full tag name (e.g., "EXIF:Make", "XMP-dc:Creator")
///
/// # Returns
/// * `Some(&TagDescriptor)` if the tag is registered
/// * `None` if the tag is not found
pub fn get_generated_tag_descriptor(name: &str) -> Option<&TagDescriptor> {
    GENERATED_TAG_REGISTRY.get(name)
}

/// Returns the total number of registered tags in the generated registry.
pub fn generated_tag_count() -> usize {
    GENERATED_TAG_REGISTRY.len()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_generated_registry_not_empty() {
        assert!(generated_tag_count() > 0, "Generated registry should not be empty");
    }

    #[test]
    fn test_generated_registry_min_count() {
        assert!(generated_tag_count() >= 500, "Expected at least 500 tags");
    }
}
